export const vec = (x: number, y: number) => {
    return new Vec(x, y)
}

vec.arg = (radian: number) => vec(Math.cos(radian), Math.sin(radian))
vec.unit = () => vec(1, 0)

export class Vec {
    x: number
    y: number

    constructor(x: number, y: number) {
        this.x = x
        this.y = y
    }

    get l(): [number, number] {
        return [this.x, this.y]
    }

    // 不変
    plus(v: Vec) {
        return vec(this.x + v.x, this.y + v.y)
    }

    minus(v: Vec) {
        return vec(this.x - v.x, this.y - v.y)
    }

    scaled(scalar: number) {
        return vec(this.x * scalar, this.y * scalar)
    }

    normalized() {
        const l = this.magnitude()

        if (l == 0) {
            return vec(0, 0)
        } else {
            return this.scaled(1 / l)
        }
    }

    rotated(radian: number) {
        return vec(
            this.x * Math.cos(radian) - this.y * Math.sin(radian),
            this.x * Math.sin(radian) + this.y * Math.cos(radian),
        )
    }

    normal() {
        const n = this.normalized()
        return vec(n.y, -n.x)
    }

    /**
     * 各成分を指定した範囲内に収めた新しいベクトルを返す
     */
    clamp(min: Vec, max: Vec) {
        return vec(Math.max(min.x, Math.min(this.x, max.x)), Math.max(min.y, Math.min(this.y, max.y)))
    }

    clone() {
        return vec(this.x, this.y)
    }

    // 変更
    add(v: Vec) {
        this.x += v.x
        this.y += v.y
    }

    sub(v: Vec) {
        this.x -= v.x
        this.y -= v.y
    }

    scale(scalar: number) {
        this.x *= scalar
        this.y *= scalar
    }

    rotate(radian: number) {
        const x = this.x * Math.cos(radian) - this.y * Math.sin(radian)
        const y = this.x * Math.sin(radian) + this.y * Math.cos(radian)

        this.x = x
        this.y = y
    }

    normalize() {
        const l = this.magnitude()

        if (l == 0) return
        this.x /= l
        this.y /= l
    }

    // スカラー
    magnitude() {
        return Math.hypot(this.x, this.y)
    }

    magnitudeSquared() {
        return this.x ** 2 + this.y ** 2
    }

    dot(v: Vec) {
        return this.x * v.x + this.y * v.y
    }

    cross(v: Vec) {
        return this.x * v.y - v.x * this.y
    }

    arg() {
        return Math.atan2(this.y, this.x)
    }
}
